// UUID hat keine Kommas (passt direkt in queryReplacement). Body-JSON wird base64-encoded
// um den Comma-Split von n8n's queryReplacement zu umgehen.
const item = $input.first().json;
const id = (item.params && item.params.id) || '';
const body = item.body || {};
const body_b64 = Buffer.from(JSON.stringify(body), 'utf8').toString('base64');
return [{ json: { id, body_b64 } }];
